import { ethers } from "ethers";

const RPC_URL = process.env.RPC_URL || "https://mainnet.infura.io/v3/YOUR_INFURA_PROJECT_ID";
const PRIVATE_KEY = process.env.PRIVATE_KEY || "YOUR_PRIVATE_KEY";

if (!RPC_URL || !PRIVATE_KEY || PRIVATE_KEY === "YOUR_PRIVATE_KEY") {
  throw new Error("Missing or invalid RPC_URL / PRIVATE_KEY configuration");
}

const provider = new ethers.JsonRpcProvider(RPC_URL);
const wallet = new ethers.Wallet(PRIVATE_KEY, provider);

export function getWallet() {
  return wallet;
}

export function getProvider() {
  return provider;
}

export async function getAddress() {
  return wallet.getAddress();
}

export async function getEthBalance(address) {
  const target = address || (await wallet.getAddress());
  const balance = await provider.getBalance(target);
  return ethers.formatEther(balance);
}

export async function sendETH(to, amountInEth, options = {}) {
  if (!ethers.isAddress(to)) {
    throw new Error("Invalid recipient address");
  }

  const tx = {
    to,
    value: ethers.parseEther(String(amountInEth)),
  };

  if (options.gasLimit) tx.gasLimit = BigInt(options.gasLimit);
  if (options.nonce !== undefined) tx.nonce = options.nonce;
  if (options.data) tx.data = options.data;

  if (options.maxFeePerGas) {
    tx.maxFeePerGas = ethers.parseUnits(String(options.maxFeePerGas), "gwei");
  }

  if (options.maxPriorityFeePerGas) {
    tx.maxPriorityFeePerGas = ethers.parseUnits(String(options.maxPriorityFeePerGas), "gwei");
  }

  if (options.gasPrice) {
    tx.gasPrice = ethers.parseUnits(String(options.gasPrice), "gwei");
  }

  const response = await wallet.sendTransaction(tx);
  const receipt = await response.wait();

  return {
    hash: response.hash,
    from: response.from,
    to: response.to,
    nonce: response.nonce,
    gasLimit: response.gasLimit?.toString(),
    blockNumber: receipt?.blockNumber,
    status: receipt?.status,
  };
}

export function getContract(contractAddress, abi, signerOrProvider = wallet) {
  if (!ethers.isAddress(contractAddress)) {
    throw new Error("Invalid contract address");
  }
  return new ethers.Contract(contractAddress, abi, signerOrProvider);
}

export async function callContractRead(contractAddress, abi, method, args = []) {
  const contract = getContract(contractAddress, abi, provider);
  if (typeof contract[method] !== "function") {
    throw new Error(`Method ${method} does not exist on contract`);
  }
  return await contract[method](...args);
}

export async function sendContractTransaction(contractAddress, abi, method, args = [], overrides = {}) {
  const contract = getContract(contractAddress, abi, wallet);
  if (typeof contract[method] !== "function") {
    throw new Error(`Method ${method} does not exist on contract`);
  }

  const txOverrides = { ...overrides };

  if (txOverrides.value !== undefined) {
    txOverrides.value = ethers.parseEther(String(txOverrides.value));
  }
  if (txOverrides.gasLimit !== undefined) {
    txOverrides.gasLimit = BigInt(txOverrides.gasLimit);
  }
  if (txOverrides.gasPrice !== undefined) {
    txOverrides.gasPrice = ethers.parseUnits(String(txOverrides.gasPrice), "gwei");
  }
  if (txOverrides.maxFeePerGas !== undefined) {
    txOverrides.maxFeePerGas = ethers.parseUnits(String(txOverrides.maxFeePerGas), "gwei");
  }
  if (txOverrides.maxPriorityFeePerGas !== undefined) {
    txOverrides.maxPriorityFeePerGas = ethers.parseUnits(String(txOverrides.maxPriorityFeePerGas), "gwei");
  }

  const response = await contract[method](...args, txOverrides);
  const receipt = await response.wait();

  return {
    hash: response.hash,
    from: response.from,
    to: response.to,
    nonce: response.nonce,
    blockNumber: receipt?.blockNumber,
    status: receipt?.status,
    gasUsed: receipt?.gasUsed?.toString(),
  };
}

export async function estimateEthTransferGas(to, amountInEth) {
  const from = await wallet.getAddress();
  const gas = await provider.estimateGas({
    from,
    to,
    value: ethers.parseEther(String(amountInEth)),
  });
  return gas.toString();
}

export async function estimateContractGas(contractAddress, abi, method, args = [], overrides = {}) {
  const contract = getContract(contractAddress, abi, wallet);
  if (!contract[method] || !contract[method].estimateGas) {
    throw new Error(`Method ${method} does not support gas estimation`);
  }

  const txOverrides = { ...overrides };

  if (txOverrides.value !== undefined) {
    txOverrides.value = ethers.parseEther(String(txOverrides.value));
  }

  const gas = await contract[method].estimateGas(...args, txOverrides);
  return gas.toString();
}

